def _tableau_dashboard_field_to_nested(
    tableau_dashboard_field: TableauDashboardField,
) -> TableauDashboardFieldNested:
    """Convert flat TableauDashboardField to nested format."""
    attrs = TableauDashboardFieldAttributes()
    _populate_tableau_dashboard_field_attrs(attrs, tableau_dashboard_field)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        tableau_dashboard_field,
        _TABLEAU_DASHBOARD_FIELD_REL_FIELDS,
        TableauDashboardFieldRelationshipAttributes,
    )
    return TableauDashboardFieldNested(
        guid=tableau_dashboard_field.guid,
        type_name=tableau_dashboard_field.type_name,
        status=tableau_dashboard_field.status,
        version=tableau_dashboard_field.version,
        create_time=tableau_dashboard_field.create_time,
        update_time=tableau_dashboard_field.update_time,
        created_by=tableau_dashboard_field.created_by,
        updated_by=tableau_dashboard_field.updated_by,
        classifications=tableau_dashboard_field.classifications,
        classification_names=tableau_dashboard_field.classification_names,
        meanings=tableau_dashboard_field.meanings,
        labels=tableau_dashboard_field.labels,
        business_attributes=tableau_dashboard_field.business_attributes,
        custom_attributes=tableau_dashboard_field.custom_attributes,
        pending_tasks=tableau_dashboard_field.pending_tasks,
        proxy=tableau_dashboard_field.proxy,
        is_incomplete=tableau_dashboard_field.is_incomplete,
        provenance_type=tableau_dashboard_field.provenance_type,
        home_id=tableau_dashboard_field.home_id,
        depth=tableau_dashboard_field.depth,
        immediate_upstream=tableau_dashboard_field.immediate_upstream,
        immediate_downstream=tableau_dashboard_field.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _tableau_dashboard_field_from_nested(
    nested: TableauDashboardFieldNested,
) -> TableauDashboardField:
    """Convert nested format to flat TableauDashboardField."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else TableauDashboardFieldAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _TABLEAU_DASHBOARD_FIELD_REL_FIELDS,
        TableauDashboardFieldRelationshipAttributes,
    )
    return TableauDashboardField(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_tableau_dashboard_field_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _tableau_dashboard_field_to_nested_bytes(
    tableau_dashboard_field: TableauDashboardField, serde: Serde
) -> bytes:
    """Convert flat TableauDashboardField to nested JSON bytes."""
    return serde.encode(_tableau_dashboard_field_to_nested(tableau_dashboard_field))


def _tableau_dashboard_field_from_nested_bytes(
    data: bytes, serde: Serde
) -> TableauDashboardField:
    """Convert nested JSON bytes to flat TableauDashboardField."""
    nested = serde.decode(data, TableauDashboardFieldNested)
    return _tableau_dashboard_field_from_nested(nested)


